INSERT INTO zfgbb.message_history (message_history_id, message_id, message_text, current_flag, created_ts, updated_ts, ip_address_id, migration_hash, legacy_id) VALUES (5, 5, '[b]Bold[/b]<br /><br />[i]Italics[/i]<br /><br />[u]Underline[/u]<br /><br />[s]Strikethrough[/s]<br /><br />[s][u][i][b]Bold, italics, underline, strikethrough combined[/b][/i][/u][/s]<br /><br />[pre]Preformatted text[/pre]<br /><br />[left]Left Align Text[/left]<br /><br />[center]Centered Text[/center]<br /><br />[right]Right Aligned[/right]<br /><br />Hyperlink<br />[url=https://youtu.be/l0sZPaz8lU4?t=1961&amp;si=G8AlSABRKJD_o0c6]https://youtu.be/l0sZPaz8lU4?t=1961&amp;si=G8AlSABRKJD_o0c6[/url]<br /><br />[glow=red,2,300]Red Glow Text[/glow]<br /><br />[shadow=red,left]Red Dropshadow Text[/shadow]<br /><br />[move]Marquee test[/move]<br /><br />[sup]Superscript test[/sup]<br />[sub]Subscript test[/sub]<br /><br />[tt]Teletype test[/tt]<br /><br />[table]<br />[tr]<br />[td]Simple table test[/td]<br />[/tr]<br />[/table]<br /><br /><br />[code]<br />function someFunction() {<br />&nbsp; console.log(&#039;code test&#039;)<br />}<br />[/code]<br /><br />[quote]<br />Quote test<br />[/quote]<br /><br />[list]<br />[li]Bullet list test[/li]<br />[li]Bullet list test[/li]<br />[/list]<br /><br />[list type=decimal]<br />[li]Decimal list test[/li]<br />[li]Decimal list test[/li]<br />[/list]<br /><br />Horizontal divider test<br />[hr]<br /><br />[size=36pt]Font Size Test[/size]<br /><br />[font=comic sans ms]Font Face Test[/font]<br /><br />[color=navy]Font Color Test[/color]<br />', true, '2026-05-02 03:50:06', '2026-05-02 03:50:06', 2, 'Nj9CZFhbvGz_4hDpWgjAQg==', NULL);
